// Rust force wipe is first Thursday of each month
// Our server also wipes first Thursday (BP wipe only on forced)
const now = new Date();
const year = now.getUTCFullYear();
const month = now.getUTCMonth();

// Find first Thursday of current month
const firstDay = new Date(Date.UTC(year, month, 1));
let firstThursday = 1 + ((4 - firstDay.getUTCDay() + 7) % 7);
const wipeDate = new Date(Date.UTC(year, month, firstThursday));

// Check if tomorrow is wipe day
const tomorrow = new Date(now);
tomorrow.setUTCDate(tomorrow.getUTCDate() + 1);

const isWipeTomorrow = tomorrow.getUTCDate() === wipeDate.getUTCDate() && 
                       tomorrow.getUTCMonth() === wipeDate.getUTCMonth();

// Also check if next week is wipe week (early warning)
const daysUntilWipe = Math.ceil((wipeDate - now) / 86400000);
const isWipeWeek = daysUntilWipe > 0 && daysUntilWipe <= 7;

return [{ json: {
  wipeDate: wipeDate.toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }),
  isWipeTomorrow,
  isWipeWeek,
  daysUntilWipe,
  shouldNotify: isWipeTomorrow || (isWipeWeek && daysUntilWipe === 7)
}}];

